import{_ as e,o as a,c as o,a2 as d}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 18 — Copy & Paste","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/18-copy-paste.md","filePath":"chapters/18-copy-paste.md"}'),s={name:"chapters/18-copy-paste.md"};function n(r,t,i,l,c,p){return a(),o("div",null,[...t[0]||(t[0]=[d(`<h1 id="chapter-18-—-copy-paste" tabindex="-1">Chapter 18 — Copy &amp; Paste <a class="header-anchor" href="#chapter-18-—-copy-paste" aria-label="Permalink to &quot;Chapter 18 — Copy &amp; Paste&quot;">​</a></h1><blockquote><p><em>&quot;In Vim, copying and pasting are called yanking and putting.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Copying and pasting in Vim uses different terminology and concepts:</p><ul><li><strong>Yank</strong> = Copy</li><li><strong>Put</strong> = Paste</li><li><strong>Registers</strong> = Multiple clipboards</li></ul><hr><h1 id="yanking-copying" tabindex="-1">Yanking (Copying) <a class="header-anchor" href="#yanking-copying" aria-label="Permalink to &quot;Yanking (Copying)&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>yy</code></td><td>Yank current line</td></tr><tr><td><code>Y</code></td><td>Yank current line (same as yy)</td></tr><tr><td><code>yw</code></td><td>Yank word</td></tr><tr><td><code>y$</code></td><td>Yank to end of line</td></tr><tr><td><code>y0</code></td><td>Yank to beginning of line</td></tr><tr><td><code>yG</code></td><td>Yank from cursor to end of file</td></tr><tr><td><code>ygg</code></td><td>Yank from cursor to beginning</td></tr><tr><td><code>y5j</code></td><td>Yank 5 lines down</td></tr></tbody></table><h2 id="visual-mode-yanking" tabindex="-1">Visual Mode Yanking <a class="header-anchor" href="#visual-mode-yanking" aria-label="Permalink to &quot;Visual Mode Yanking&quot;">​</a></h2><ol><li>Select text with <code>v</code>, <code>V</code>, or <code>Ctrl+v</code>.</li><li>Press <code>y</code> to yank.</li></ol><hr><h1 id="putting-pasting" tabindex="-1">Putting (Pasting) <a class="header-anchor" href="#putting-pasting" aria-label="Permalink to &quot;Putting (Pasting)&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>p</code></td><td>Put (paste) <strong>after</strong> cursor</td></tr><tr><td><code>P</code></td><td>Put (paste) <strong>before</strong> cursor</td></tr><tr><td><code>gp</code></td><td>Put after cursor, then move cursor to end</td></tr><tr><td><code>gP</code></td><td>Put before cursor, then move cursor to end</td></tr></tbody></table><h2 id="with-counts" tabindex="-1">With Counts <a class="header-anchor" href="#with-counts" aria-label="Permalink to &quot;With Counts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>3p</code></td><td>Paste 3 times</td></tr><tr><td><code>5P</code></td><td>Paste 5 times before</td></tr></tbody></table><hr><h1 id="registers-multiple-clipboards" tabindex="-1">Registers (Multiple Clipboards) <a class="header-anchor" href="#registers-multiple-clipboards" aria-label="Permalink to &quot;Registers (Multiple Clipboards)&quot;">​</a></h1><p>Vim has <strong>registers</strong> — named storage locations for text.</p><table tabindex="0"><thead><tr><th>Register</th><th>Name</th><th>Contents</th></tr></thead><tbody><tr><td><code>&quot;</code></td><td>Unnamed</td><td>Last yank or delete</td></tr><tr><td><code>0</code></td><td>Yank</td><td>Last yank (not delete)</td></tr><tr><td><code>1</code>-<code>9</code></td><td>Delete history</td><td>Last 9 deletes</td></tr><tr><td><code>a</code>-<code>z</code></td><td>Named</td><td>User-defined storage</td></tr><tr><td><code>+</code></td><td>System clipboard</td><td>System clipboard (OS clipboard)</td></tr><tr><td><code>*</code></td><td>Selection clipboard</td><td>Mouse selection</td></tr><tr><td><code>_</code></td><td>Black hole</td><td>Discard text (like /dev/null)</td></tr></tbody></table><h2 id="using-registers" tabindex="-1">Using Registers <a class="header-anchor" href="#using-registers" aria-label="Permalink to &quot;Using Registers&quot;">​</a></h2><p>To use a register, prefix the command with <code>&quot;</code> and the register name:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;ayy        →   Yank current line into register a</span></span>
<span class="line"><span>&quot;ap         →   Paste from register a</span></span>
<span class="line"><span>&quot;0p         →   Paste last yanked text (even after delete)</span></span>
<span class="line"><span>&quot;+p         →   Paste from system clipboard</span></span>
<span class="line"><span>&quot;+yy        →   Yank into system clipboard</span></span></code></pre></div><h2 id="viewing-registers" tabindex="-1">Viewing Registers <a class="header-anchor" href="#viewing-registers" aria-label="Permalink to &quot;Viewing Registers&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:reg</span></span></code></pre></div><p>Shows all registers and their contents.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:reg a b c</span></span></code></pre></div><p>Shows specific registers.</p><hr><h1 id="the-black-hole-register" tabindex="-1">The Black Hole Register <a class="header-anchor" href="#the-black-hole-register" aria-label="Permalink to &quot;The Black Hole Register&quot;">​</a></h1><p>Sometimes you want to delete text without storing it.</p><p>Use the black hole register:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;_dd       →   Delete line without saving to any register</span></span>
<span class="line"><span>&quot;_dw       →   Delete word without saving</span></span></code></pre></div><hr><h1 id="swapping-text" tabindex="-1">Swapping Text <a class="header-anchor" href="#swapping-text" aria-label="Permalink to &quot;Swapping Text&quot;">​</a></h1><p>A common editing task: swap two words or lines.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>apple banana</span></span>
<span class="line"><span>^ cursor on apple</span></span>
<span class="line"><span></span></span>
<span class="line"><span>To swap: &quot;apple banana&quot; → &quot;banana apple&quot;:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>dw          →   delete &quot;apple &quot; (store in register &quot;)</span></span>
<span class="line"><span>e           →   move to end of &quot;banana&quot;</span></span>
<span class="line"><span>p           →   put &quot;apple &quot; after &quot;banana&quot;</span></span></code></pre></div><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>yy</code></td><td>Yank line</td></tr><tr><td><code>yw</code></td><td>Yank word</td></tr><tr><td><code>y$</code></td><td>Yank to end of line</td></tr><tr><td><code>p</code></td><td>Put after cursor</td></tr><tr><td><code>P</code></td><td>Put before cursor</td></tr><tr><td><code>&quot;ayy</code></td><td>Yank to register a</td></tr><tr><td><code>&quot;ap</code></td><td>Paste from register a</td></tr><tr><td><code>&quot;+y</code></td><td>Yank to system clipboard</td></tr><tr><td><code>:reg</code></td><td>View registers</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>yy</code> yanks a line, <code>p</code> pastes it.</li><li>Deleted text is also stored in registers — you can paste it.</li><li>Use <code>&quot;a</code>-<code>&quot;z</code> for named registers (multiple clipboards).</li><li>Use <code>&quot;+</code> for the system clipboard.</li><li><code>:reg</code> shows all register contents.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Yank a line with <code>yy</code> and paste it multiple times with <code>p</code>.</li><li>Yank a word with <code>yw</code> and paste it elsewhere.</li><li>Store text in register <code>a</code> with <code>&quot;ayy</code>, then paste with <code>&quot;ap</code>.</li><li>Copy text from another application and paste into Vim with <code>&quot;+p</code>.</li><li>View all registers with <code>:reg</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./19-undo-redo.html"><strong>Chapter 19 — Undo / Redo</strong></a></p><p>Learn how to undo and redo changes in Vim, including branching undo history.</p>`,52)])])}const g=e(s,[["render",n]]);export{u as __pageData,g as default};
